import React, { useState, useRef, useCallback, useEffect } from 'react';
import { GoogleOAuthProvider, GoogleLogin, googleLogout } from '@react-oauth/google';
import './App.css';

const API_BASE = 'http://127.0.0.1:8000';
const GOOGLE_CLIENT_ID = '80369468349-jlbunn8ubumo4kutgl2aed9dqkv2rf97.apps.googleusercontent.com'; // Replace with your Google Client ID

const genres = [
  { id: 'rock', name: 'Rock' },
  { id: 'pop', name: 'Pop' },
  { id: 'jazz', name: 'Jazz' },
  { id: 'classical', name: 'Classical' },
  { id: 'hip-hop', name: 'Hip-Hop' },
  { id: 'electronic', name: 'Electronic' },
  { id: 'indie', name: 'Indie' },
  { id: 'r&b', name: 'R&B' },
  { id: 'country', name: 'Country' },
  { id: 'metal', name: 'Metal' },
  { id: 'latin', name: 'Latin' },
  { id: 'folk', name: 'Folk' },
];

const moods = [
  { id: 'happy', name: 'Happy', emoji: '☀️' },
  { id: 'energetic', name: 'Energetic', emoji: '⚡' },
  { id: 'relaxing', name: 'Relaxing', emoji: '🌊' },
  { id: 'romantic', name: 'Romantic', emoji: '💜' },
  { id: 'sad', name: 'Sad', emoji: '🌧️' },
  { id: 'focus', name: 'Focus', emoji: '🎯' },
  { id: 'party', name: 'Party', emoji: '🎉' },
  { id: 'workout', name: 'Workout', emoji: '💪' },
  { id: 'chill', name: 'Chill', emoji: '😌' },
];

function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [user, setUser] = useState(null);
  const [token, setToken] = useState('');
  const [selectedGenre, setSelectedGenre] = useState('');
  const [selectedMood, setSelectedMood] = useState('');
  const [selectedArtist, setSelectedArtist] = useState('');
  const [songCount, setSongCount] = useState(10);
  const [playlist, setPlaylist] = useState([]);
  const [userPlaylists, setUserPlaylists] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // Audio player state
  const audioRef = useRef(null);
  const [currentSongId, setCurrentSongId] = useState(null);
  const [isPlaying, setIsPlaying] = useState(false);

  // Cleanup audio on unmount
  useEffect(() => {
    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
      }
    };
  }, []);

  const togglePlayPause = useCallback((songId, previewUrl) => {
    if (!previewUrl) return;

    if (currentSongId === songId && isPlaying) {
      audioRef.current.pause();
      setIsPlaying(false);
    } else {
      if (audioRef.current) {
        audioRef.current.pause();
      }
      
      const audio = new Audio(previewUrl);
      audioRef.current = audio;
      audio.play().catch(e => console.error('Audio play failed:', e));
      
      setCurrentSongId(songId);
      setIsPlaying(true);
      
      audio.onended = () => {
        setIsPlaying(false);
        setCurrentSongId(null);
      };
    }
  }, [currentSongId, isPlaying]);

  const handleLoginSuccess = async (credentialResponse) => {
    const token = credentialResponse.credential;
    setToken(token);
    localStorage.setItem('token', token);
    
    try {
      const payload = JSON.parse(atob(token.split('.')[1]));
      setUser({
        name: payload.name,
        email: payload.email,
        picture: payload.picture
      });
      setIsLoggedIn(true);
    } catch (err) {
      setError('Login failed');
    }
  };

  const handleLoginError = () => {
    setError('Login failed');
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setUser(null);
    setToken('');
    setUserPlaylists([]);
    localStorage.removeItem('token');
    googleLogout();
  };

  const getAuthHeaders = () => {
    if (token) {
      return {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json'
      };
    }
    return {
      'Content-Type': 'application/json'
    };
  };

  const handleGenerate = async (e) => {
    e.preventDefault();
    
    if (audioRef.current) {
      audioRef.current.pause();
      setCurrentSongId(null);
      setIsPlaying(false);
    }

    setLoading(true);
    setError('');
    setPlaylist([]);

    try {
      const params = new URLSearchParams();
      if (selectedGenre) params.append('genre', selectedGenre);
      if (selectedMood) params.append('mood', selectedMood);
      if (selectedArtist) params.append('artist', selectedArtist);
      params.append('limit', songCount);

      const response = await fetch(`${API_BASE}/custom?${params}`, {
        headers: getAuthHeaders()
      });
      
      if (!response.ok) {
        throw new Error(`API error: ${response.status}`);
      }
      
      const data = await response.json();
      setPlaylist(data.playlist || []);
    } catch (err) {
      setError(err.message || 'Failed to generate playlist. Is backend running?');
    } finally {
      setLoading(false);
    }
  };

  const savePlaylist = async (currentPlaylist) => {
    if (!token) {
      setError('Please log in to save playlists');
      return;
    }

    try {
      setLoading(true);
      const playlistData = {
        name: `My ${selectedGenre || 'Perfect'} Playlist`,
        songs: currentPlaylist,
        preferences: {
          genre: selectedGenre,
          mood: selectedMood,
          artist: selectedArtist
        }
      };

      const response = await fetch(`${API_BASE}/playlists/`, {
        method: 'POST',
        headers: getAuthHeaders(),
        body: JSON.stringify(playlistData)
      });

      if (response.ok) {
        alert('Playlist saved successfully!');
        loadUserPlaylists();
      } else {
        throw new Error('Failed to save playlist');
      }
    } catch (err) {
      setError('Failed to save playlist: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  const loadUserPlaylists = async () => {
    if (!token) return;
    
    try {
      const response = await fetch(`${API_BASE}/playlists`, {
        headers: getAuthHeaders()
      });
      if (response.ok) {
        const data = await response.json();
        setUserPlaylists(data);
      }
    } catch (err) {
      console.error('Failed to load playlists');
    }
  };

  const defaultArtwork = 'https://via.placeholder.com/120x120/1a1a1d/666666?text=Music';

  if (!isLoggedIn) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-purple-900 via-blue-900 to-indigo-900 text-white p-8 flex items-center justify-center">
        <div className="text-center max-w-md login-card">
          <div className="music-note">🎵</div>
          <h1 className="text-4xl md:text-5xl font-bold gradient-text mb-6">
            Music Playlist Generator
          </h1>
          <p className="text-xl opacity-90 mb-12 leading-relaxed">
            Log in with Google to create, save, and share your perfect playlists
          </p>
          <GoogleLogin
            onSuccess={handleLoginSuccess}
            onError={handleLoginError}
            theme="filled_blue"
            size="large"
            text="signin_with"
            shape="rectangular"
            width="300"
          />
          {error && (
            <div className="mt-6 p-4 bg-red-500/20 border border-red-500/50 rounded-2xl text-red-100 text-sm">
              {error}
            </div>
          )}
          <p className="text-sm opacity-75 mt-8">Your playlists sync across devices</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-purple-900 via-blue-900 to-indigo-900 text-white p-8">
      <div className="max-w-6xl mx-auto">
        <header className="text-center mb-16">
          <div className="flex items-center justify-center gap-6 mb-8 p-6 bg-white/10 backdrop-blur-lg rounded-3xl inline-flex">
            <img src={user.picture} alt={user.name} className="w-16 h-16 rounded-full ring-2 ring-white/30 shadow-lg" />
            <div>
              <h1 className="text-5xl md:text-6xl font-bold bg-gradient-to-r from-purple-400 via-pink-400 to-blue-400 bg-clip-text text-transparent mb-2">
                🎵 Music Playlist Generator
              </h1>
              <p className="text-xl opacity-90">{user.name}</p>
            </div>
          </div>
          <button
            onClick={handleLogout}
            className="btn-secondary inline-flex items-center gap-2"
          >
            🚪 Logout
          </button>
        </header>

        {/* Your Playlists */}
        <div className="glass-card mb-16">
          <div className="flex items-center gap-4 mb-8">
            <div className="w-12 h-12 bg-green-500/20 rounded-2xl flex items-center justify-center">
              <span className="text-2xl">📚</span>
            </div>
            <h2 className="text-3xl font-bold gradient-text">
              Your Playlists ({userPlaylists.length})
            </h2>
          </div>
          <button 
            onClick={loadUserPlaylists}
            className="btn-primary inline-flex items-center gap-2 mb-8"
          >
            🔄 Refresh Playlists
          </button>
          {userPlaylists.length === 0 ? (
            <div className="text-center py-16">
              <div className="text-6xl mb-4 opacity-20">📭</div>
              <p className="text-xl opacity-75 mb-4">No playlists yet</p>
              <p className="text-gray-300">Generate your first playlist below!</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {userPlaylists.map(playlist => (
                <div key={playlist.id} className="playlist-item cursor-pointer hover:bg-white/30 p-6 rounded-2xl">
                  <h3 className="font-bold text-lg mb-2 gradient-text">{playlist.name}</h3>
                  <p className="text-lg opacity-75 mb-4">{playlist.songs.length} songs</p>
                  <div className="flex gap-2">
                    <span className="px-3 py-1 bg-white/20 rounded-full text-xs">{playlist.preferences?.genre || 'Mixed'}</span>
                    <span className="px-3 py-1 bg-white/20 rounded-full text-xs">{playlist.preferences?.mood || 'Various'}</span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Generate New Playlist */}
        <form onSubmit={handleGenerate} className="glass-card mb-16">
          <div className="flex items-center gap-4 mb-10">
            <div className="w-12 h-12 bg-purple-500/20 rounded-2xl flex items-center justify-center">
              <span className="text-2xl">✨</span>
            </div>
            <h2 className="text-3xl font-bold gradient-text">
              Create New Playlist
            </h2>
          </div>
          <div className="grid md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
            {/* Genre */}
            <div className="form-group">
              <label>Genre</label>
              <select 
                value={selectedGenre} 
                onChange={(e) => setSelectedGenre(e.target.value)}
                className="form-group"
              >
                <option value="">Any Genre</option>
                {genres.map(genre => (
                  <option key={genre.id} value={genre.id}>{genre.name}</option>
                ))}
              </select>
            </div>

            {/* Mood */}
            <div className="form-group">
              <label>Mood</label>
              <select 
                value={selectedMood} 
                onChange={(e) => setSelectedMood(e.target.value)}
                className="form-group"
              >
                <option value="">Any Mood</option>
                {moods.map(mood => (
                  <option key={mood.id} value={mood.id}>{mood.emoji} {mood.name}</option>
                ))}
              </select>
            </div>

            {/* Artist */}
            <div className="form-group">
              <label>Artist (optional)</label>
              <input 
                type="text" 
                value={selectedArtist}
                onChange={(e) => setSelectedArtist(e.target.value)}
                placeholder="Taylor Swift, Drake..."
                className="form-group"
              />
            </div>

            {/* Song Count */}
            <div className="form-group">
              <label>Number of Songs</label>
              <div className="flex items-center gap-4">
                <input 
                  type="range" 
                  min="5" max="50" step="5"
                  value={songCount}
                  onChange={(e) => setSongCount(Number(e.target.value))}
                  className="flex-1"
                />
                <span className="font-mono text-2xl font-bold min-w-[3rem] text-center">{songCount}</span>
              </div>
            </div>
          </div>

          <button 
            type="submit" 
            disabled={loading}
            className="btn-primary w-full mt-12 text-lg py-5 font-semibold"
          >
            {loading ? (
              <>
                <span className="animate-spin mr-3">🎧</span>
                Generating your perfect playlist...
              </>
            ) : (
              <>
                ✨ Generate My Perfect Playlist ({songCount} songs)
              </>
            )}
          </button>

          {error && (
            <div className="mt-8 p-6 bg-red-500/20 border border-red-500/50 rounded-2xl text-red-100">
              {error}
            </div>
          )}
        </form>

        {playlist.length > 0 && (
          <div className="glass-card">
            <div className="flex items-center gap-4 mb-12">
              <div className="w-12 h-12 bg-emerald-500/20 rounded-2xl flex items-center justify-center">
                <span className="text-2xl">🎶</span>
              </div>
              <h2 className="text-3xl font-bold gradient-text">
                Your Generated Playlist ({playlist.length} songs)
              </h2>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
              {playlist.map((song, index) => (
                <div key={`${song.id}-${index}`} className="song-card group glass-card p-8 h-[420px] flex flex-col">
                  <div className="relative flex-1 mb-6">
                    <img 
                      src={song.artwork || defaultArtwork} 
                      alt={song.title}
                      className="w-full h-64 object-cover rounded-2xl shadow-2xl"
                    />
                    <div className="play-button bg-gradient-to-br from-emerald-400 to-teal-500 text-white shadow-2xl group-hover:scale-110">
                      {currentSongId === index && isPlaying ? '⏸️' : '▶️'}
                    </div>
                  </div>
                  
                  <div className="flex-1 flex flex-col justify-between">
                    <div>
                      <h3 className="font-bold text-xl mb-1 line-clamp-1 gradient-text">{song.title}</h3>
                      <p className="text-lg opacity-80 mb-2">{song.artist}</p>
                      <p className="text-sm opacity-60">{song.album}</p>
                    </div>
                    
                    <button 
                      onClick={() => savePlaylist(playlist)}
                      className="btn-primary w-full mt-4 text-sm py-3"
                    >
                      💾 Save to My Playlists
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

function Root() {
  return (
    <GoogleOAuthProvider clientId={GOOGLE_CLIENT_ID}>
      <App />
    </GoogleOAuthProvider>
  );
}

export default Root;
